#include <string.h>

static inline int em_check_ros1_xmlrpc_injection(const char *payload) {
    if (payload == NULL) return 0;

    // Verify this looks like an XML-RPC request
    if (strstr(payload, "<?xml") == NULL &&
        strstr(payload, "<methodCall>") == NULL) return 0;

    // Suspicious ROS Master XML-RPC methods
    static const char *methods[] = {
        // Reconnaissance methods
        "getSystemState",
        "getTopicTypes",
        "getPublishedTopics",
        "lookupNode",
        "lookupService",
        "getUri",
        // Injection / manipulation methods
        "registerPublisher",
        "registerSubscriber",
        "unregisterPublisher",
        "unregisterSubscriber",
        "registerService",
        "unregisterService"
    };
    static const int num_methods = sizeof(methods) / sizeof(methods[0]);

    // Look for <methodName> tag
    const char *method_start = strstr(payload, "<methodName>");
    if (method_start == NULL) return 0;

    int i;
    for (i = 0; i < num_methods; i++) {
        if (strstr(method_start, methods[i]) != NULL) {
            return 1;
        }
    }

    return 0;
}
